import { Component, OnInit, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule } from '@angular/router';
import { AlumnoDashboardService, AlumnoCertificado } from '../../../core/services/alumno-dashboard.service';
import { AuthService } from '../../../core/services/auth.service';

@Component({
  selector: 'app-certificados',
  standalone: true,
  imports: [CommonModule, RouterModule],
  templateUrl: './certificados.component.html',
  styleUrls: ['./certificados.component.css']
})
export class CertificadosComponent implements OnInit {
  private studentService = inject(AlumnoDashboardService);
  private authService = inject(AuthService);

  certificados: AlumnoCertificado[] = [];
  isLoading = true;
  isAdmin = false;

  ngOnInit(): void {
    this.isAdmin = this.authService.getUserRole() === 'ADMINISTRADOR';
    if (this.isAdmin) {
      this.isLoading = false;
      return;
    }

    this.studentService.getCertificados().subscribe({
      next: (data) => {
        this.certificados = data;
        this.isLoading = false;
      },
      error: (err) => {
        console.error('Error fetching certificates:', err);
        this.isLoading = false;
      }
    });
  }

  exportarCSV(): void {
    const token = this.authService.getToken();
    window.open(`http://localhost:8080/api/reportes/certificados?token=${token}`, '_blank');
  }

  getToken(): string | null {
    return this.authService.getToken();
  }
}
<div class="space-y-8 font-body">

  <!-- Banner Header for Admin -->
  <div *ngIf="isAdmin" class="border border-slate-200 p-8 bg-white rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] flex items-center justify-between">
    <div>
      <h1 class="text-2xl font-black text-slate-900 tracking-tight uppercase leading-none">Reporte de Certificados</h1>
      <p class="text-slate-500 text-xs mt-2">Exporta la lista de certificados oficiales emitidos a los alumnos registrados.</p>
    </div>
    <button 
      (click)="exportarCSV()" 
      class="px-4 py-2 bg-slate-900 hover:bg-slate-800 text-white text-[10px] font-bold uppercase tracking-widest transition-colors flex items-center gap-2 rounded-none">
      <span class="material-symbols-outlined text-sm">download</span>
      <span>Exportar CSV</span>
    </button>
  </div>

  <!-- Banner Header for Student -->
  <div *ngIf="!isAdmin" class="border border-slate-200 p-8 bg-white rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)]">
    <h1 class="text-2xl font-black text-slate-900 tracking-tight uppercase leading-none">Mis Certificados</h1>
    <p class="text-slate-500 text-xs mt-2">Visualiza y descarga los certificados oficiales obtenidos tras culminar exitosamente tus cursos.</p>
  </div>

  <!-- Loading State -->
  <div *ngIf="isLoading && !isAdmin" class="flex flex-col items-center justify-center p-20 border border-slate-200 bg-white">
    <span class="animate-spin inline-block w-8 h-8 border-4 border-primary border-t-transparent rounded-full mb-3"></span>
    <span class="text-xs font-bold text-slate-500 uppercase tracking-widest">Cargando tus certificados...</span>
  </div>

  <!-- No certificates state -->
  <div *ngIf="!isLoading && !isAdmin && certificados.length === 0" class="border border-slate-200 p-12 text-center bg-white">
    <span class="material-symbols-outlined text-5xl text-slate-300 mb-2">workspace_premium</span>
    <h3 class="text-sm font-bold text-slate-800 uppercase">Sin certificados obtenidos</h3>
    <p class="text-slate-500 text-xs mt-1.5 max-w-sm mx-auto">Completa el 100% de la carga académica de cualquiera de tus cursos inscritos para desbloquear automáticamente la emisión del certificado.</p>
  </div>

  <!-- Certificates Table -->
  <div *ngIf="!isLoading && !isAdmin && certificados.length > 0" class="border border-slate-200 bg-white rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] overflow-hidden">
    <div class="overflow-x-auto">
      <table class="w-full text-left border-collapse text-xs">
        <thead>
          <tr class="border-b border-slate-200 bg-slate-100/60 text-slate-700 font-bold uppercase tracking-wider text-[10px]">
            <th class="p-4">Curso Completado</th>
            <th class="p-4">Código de Registro</th>
            <th class="p-4">Fecha de Emisión</th>
            <th class="p-4 text-right">Descargas</th>
          </tr>
        </thead>
        <tbody class="divide-y divide-slate-100">
          <tr *ngFor="let cert of certificados" class="hover:bg-slate-50 transition-colors">
            <!-- Curso -->
            <td class="p-4 font-bold text-slate-900 uppercase tracking-tight">
              {{ cert.cursoNombre }}
            </td>
            <!-- Código -->
            <td class="p-4 font-mono font-bold text-[10px] text-slate-600">
              {{ cert.codigo }}
            </td>
            <!-- Fecha -->
            <td class="p-4 text-slate-500 font-mono text-[10px]">
              {{ cert.fechaEmision | date:'dd/MM/yyyy HH:mm' }}
            </td>
            <!-- Acciones -->
            <td class="p-4 text-right">
              <div class="inline-flex gap-2">
                <!-- PDF Download simulated -->
                <a 
                  [href]="cert.archivoPdf + '?token=' + getToken()"
                  target="_blank"
                  title="Descargar Certificado PDF" 
                  class="p-2 border border-slate-200 hover:border-slate-400 hover:bg-slate-50 text-slate-700 rounded-none transition-colors inline-flex items-center gap-1.5 text-[10px] font-bold uppercase tracking-wider">
                  <span class="material-symbols-outlined text-sm">download</span>
                  <span>PDF</span>
                </a>
                <!-- Validate link -->
                <a 
                  [href]="cert.urlValidacion" 
                  target="_blank"
                  title="Validar Certificado" 
                  class="p-2 border border-slate-200 hover:border-slate-400 hover:bg-slate-50 text-slate-700 rounded-none transition-colors inline-flex items-center gap-1.5 text-[10px] font-bold uppercase tracking-wider">
                  <span class="material-symbols-outlined text-sm">verified_user</span>
                  <span>Validar</span>
                </a>
              </div>
            </td>
          </tr>
        </tbody>
      </table>
    </div>
  </div>

</div>
